// Java 25 exam prep - Console input
// Learn: read text with Scanner and System.console() safely.
Scanner scanner = new Scanner(System.in);
String fallback = scanner.nextLine();
Console console = System.console(); // Often null inside IDEs and redirected runs.
String name = console == null
    ? fallback
    : console.readLine("Name: ");
System.out.println(name.trim());
